/* ══════════════════════════════════════
       BLOCK: sidebar-pricing
       Scoped under .block-sidebar-pricing
       ══════════════════════════════════════ */

    .block-sidebar-pricing {
      max-width: 360px;
      width: 100%;
      height: auto;
      box-sizing: border-box;
      background: hsl(var(--bg-surface));
      border: 1px solid hsl(var(--brand-biege));
      border-radius: var(--rounded-2xl);
      padding: var(--spacing-2xl);
      display: flex;
      flex-direction: column;
      align-items: center;
      overflow: hidden;
    }

    .block-sidebar-pricing__price-row {
      display: flex;
      align-items: center;
      justify-content: flex-end;
      width: 100%;
      padding-bottom: var(--spacing-2xl);
      border-bottom: 1px dashed hsl(var(--brand-biege));
    }

    .block-sidebar-pricing__price-row--has-discount {
      justify-content: space-between;
    }

    .block-sidebar-pricing__regular {
      display: flex;
      align-items: center;
      gap: var(--spacing-2xs);
    }

    .block-sidebar-pricing__label {
      font-size: var(--text-base-font-size);
      line-height: var(--text-base-line-height);
      font-weight: var(--font-weight-semibold);
      color: hsl(var(--text-muted));
      white-space: nowrap;
    }

    .block-sidebar-pricing__badge {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      padding: var(--spacing-xs) var(--spacing-md);
      border-radius: var(--rounded-full);
      background: hsl(var(--tag-price-bg));
      font-size: var(--text-base-font-size);
      line-height: var(--text-base-line-height);
      font-weight: var(--font-weight-semibold);
      color: hsl(var(--tag-price-fg));
      white-space: nowrap;
    }

    .block-sidebar-pricing__badge--struck {
      text-decoration: line-through;
      color: hsl(var(--text-secondary));
    }

    .block-sidebar-pricing__discount {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      padding: var(--spacing-xs) var(--spacing-md);
      border-radius: var(--rounded-full);
      background: hsl(var(--brand-green));
      font-size: var(--text-base-font-size);
      line-height: var(--text-base-line-height);
      font-weight: var(--font-weight-semibold);
      color: hsl(var(--brand-shade-950));
      white-space: nowrap;
    }

    .block-sidebar-pricing__discount:empty {
      display: none;
    }

    .block-sidebar-pricing__buttons {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: var(--spacing-md);
      width: 100%;
      padding: var(--spacing-2xl) 0 var(--spacing-lg);
    }

    .block-sidebar-pricing__footer {
      width: 100%;
      padding-top: var(--spacing-xs);
      text-align: center;
      font-size: var(--text-sm-font-size);
      line-height: var(--text-sm-line-height);
      font-weight: var(--font-weight-medium);
      color: hsl(var(--text-muted));
    }

js:
const block = document.querySelector('.block-sidebar-pricing');
    if (block) {
      const discount = block.querySelector('.block-sidebar-pricing__discount');
      const priceRow = block.querySelector('.block-sidebar-pricing__price-row');
      if (discount && discount.textContent.trim()) {
        priceRow.classList.add('block-sidebar-pricing__price-row--has-discount');
        const badge = block.querySelector('.block-sidebar-pricing__badge');
        if (badge) badge.classList.add('block-sidebar-pricing__badge--struck');
      }

      const io = new IntersectionObserver((entries) => {
        entries.forEach(e => {
          if (e.isIntersecting) {
            e.target.classList.add('visible');
            io.unobserve(e.target);
          }
        });
      }, { threshold: 0.15 });
      block.querySelectorAll('.reveal').forEach(el => io.observe(el));
    }
